import{c as e,Q as a,j as i,m as o}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"AgentOpt v0.1 Technical Report: Client-Side Optimization for LLM-Based Agent","description":"","frontmatter":{"title":"AgentOpt v0.1 Technical Report: Client-Side Optimization for LLM-Based Agent","authors":"Wenyue Hua, Sripad Karne, Qian Xie, Armaan Agrawal, Nikos Pagonas, Kostis Kaffes, Tianyi Peng","published":"2026-04-07T00:00:00.000Z","source":"https://arxiv.org/abs/2604.06296"},"headers":[],"relativePath":"research/agent-harness/references/2026-04-07-agentopt-client-side-optimization.md","filePath":"research/agent-harness/references/2026-04-07-agentopt-client-side-optimization.md","lastUpdated":1779901665000}'),n={name:"research/agent-harness/references/2026-04-07-agentopt-client-side-optimization.md"};function r(s,t,l,d,c,h){return a(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="agentopt-v0-1-technical-report-client-side-optimization-for-llm-based-agent" tabindex="-1">AgentOpt v0.1 Technical Report: Client-Side Optimization for LLM-Based Agent <a class="header-anchor" href="#agentopt-v0-1-technical-report-client-side-optimization-for-llm-based-agent" aria-label="Permalink to &quot;AgentOpt v0.1 Technical Report: Client-Side Optimization for LLM-Based Agent&quot;">​</a></h1><p><strong>Authors</strong>: Wenyue Hua, Sripad Karne, Qian Xie, Armaan Agrawal, Nikos Pagonas, Kostis Kaffes, Tianyi Peng<br><strong>Published</strong>: April 7, 2026 (v1); revised April 15, 2026 (v2)<br><strong>Source</strong>: <a href="https://arxiv.org/abs/2604.06296" target="_blank" rel="noreferrer">https://arxiv.org/abs/2604.06296</a><br><strong>arXiv ID</strong>: 2604.06296<br><strong>Categories</strong>: cs.LG, cs.AI, cs.MA, cs.SE<br><strong>Code</strong>: <a href="https://agentoptimizer.github.io/agentopt/" target="_blank" rel="noreferrer">https://agentoptimizer.github.io/agentopt/</a><br><strong>License</strong>: CC BY 4.0</p><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>AI agents are increasingly deployed in real-world applications, including systems such as Manus, OpenClaw, and coding agents. Existing research has primarily focused on server-side efficiency, proposing methods such as caching, speculative execution, traffic scheduling, and load balancing to reduce the cost of serving agentic workloads. However, as users increasingly construct agents by composing local tools, remote APIs, and diverse models, an equally important optimization problem arises on the client side.</p><p>AgentOpt is introduced as a framework-agnostic Python package for client-side optimization of LLM-based agent pipelines. Across four benchmarks, the cost gap between the best and worst model combinations at matched accuracy ranges from 13× to 32×. Critically, optimal model combinations often differ from predictions based on standalone model capability rankings, demonstrating that models must be evaluated in workflow context, not isolation. The UCB-E algorithm achieves a 62–76% reduction in evaluation budget relative to brute-force search while recovering near-optimal accuracy.</p><h2 id="_1-introduction" tabindex="-1">1. Introduction <a class="header-anchor" href="#_1-introduction" aria-label="Permalink to &quot;1. Introduction&quot;">​</a></h2><p>As AI agents become more prevalent in real-world deployments, developers increasingly compose pipelines from heterogeneous components: local tools, remote APIs, and diverse language models. While server-side optimization (caching, speculative execution, traffic scheduling, load balancing) has received significant research attention, client-side optimization — how developers should allocate resources across pipeline stages — remains underexplored.</p><p>AgentOpt formalizes this as a client-side optimization problem: given a multi-step agent pipeline, a pool of candidate models, and a labeled evaluation set, find the assignment of models to pipeline stages that maximizes accuracy subject to cost and latency constraints (or, equivalently, constructs the Pareto frontier over these objectives).</p><p>The key insight motivating this work is that <strong>individual model capability does not predict combination performance</strong>. A stronger model assigned to the wrong pipeline role can actively harm end-to-end accuracy. The most striking demonstration: on HotpotQA, Claude Opus 4.6 used as the planner in a 2-stage planner-solver pipeline achieves only 31.71% accuracy — it ranks worst among all 81 model combinations tested — because it attempts to answer queries directly rather than delegating to the downstream solver. Replacing it with Ministral 3 8B as planner (while keeping Opus 4.6 as solver) yields 74.27% accuracy.</p><h3 id="_1-1-problem-distinction-from-llm-routing" tabindex="-1">1.1 Problem Distinction from LLM Routing <a class="header-anchor" href="#_1-1-problem-distinction-from-llm-routing" aria-label="Permalink to &quot;1.1 Problem Distinction from LLM Routing&quot;">​</a></h3><p>AgentOpt addresses a fundamentally different problem from per-query LLM routing:</p><table tabindex="0"><thead><tr><th>LLM Routing</th><th>AgentOpt (Pipeline Optimization)</th></tr></thead><tbody><tr><td>Per-query decisions</td><td>Pipeline-level optimization</td></tr><tr><td>Single LLM call</td><td>Multi-stage pipeline with coupled assignments</td></tr><tr><td>No inter-stage dependency</td><td>Downstream quality depends on upstream output</td></tr><tr><td>Query-time selection</td><td>Design-time configuration search</td></tr></tbody></table><p>Client-side optimization is &quot;the layer at which application-specific objectives can be expressed directly,&quot; complementing server-side efficiency improvements.</p><h2 id="_2-problem-formulation" tabindex="-1">2. Problem Formulation <a class="header-anchor" href="#_2-problem-formulation" aria-label="Permalink to &quot;2. Problem Formulation&quot;">​</a></h2><p>Given:</p><ul><li>An agent pipeline $P$ consisting of $k$ stages, each invoking an LLM</li><li>A candidate model pool $\\mathcal{M}$ of size $n$</li><li>A labeled evaluation set $\\mathcal{D}$ of input/output pairs</li><li>A utility function $U$ over (accuracy, cost, latency)</li></ul><p>AgentOpt searches for the assignment $\\mathbf{m} = (m_1, \\ldots, m_k) \\in \\mathcal{M}^k$ that maximizes $U$, or equivalently constructs the Pareto frontier over accuracy, cost, and latency objectives.</p><p>The combinatorial search space has size $n^k$. For a 2-stage pipeline with 9 models, this yields 81 combinations. Exhaustive evaluation is prohibitively expensive; AgentOpt uses bandit-style algorithms to achieve sample-efficient search.</p><h2 id="_3-technical-architecture" tabindex="-1">3. Technical Architecture <a class="header-anchor" href="#_3-technical-architecture" aria-label="Permalink to &quot;3. Technical Architecture&quot;">​</a></h2><h3 id="_3-1-framework-agnostic-http-interception" tabindex="-1">3.1 Framework-Agnostic HTTP Interception <a class="header-anchor" href="#_3-1-framework-agnostic-http-interception" aria-label="Permalink to &quot;3.1 Framework-Agnostic HTTP Interception&quot;">​</a></h3><p>AgentOpt intercepts LLM calls at the <strong>httpx transport layer</strong> by patching <code>httpx.Client.send()</code>. This approach:</p><ul><li>Requires <strong>no modifications to agent code</strong></li><li>Works with any framework that uses httpx for HTTP (LangChain, AutoGen, CrewAI, custom pipelines)</li><li>Attributes each LLM call to specific (datapoint, combination) pairs using Python <code>contextvars</code></li></ul><p>The interception layer transparently replaces model identifiers in outgoing requests, routing calls to the assigned model for each stage.</p><h3 id="_3-2-combination-evaluation" tabindex="-1">3.2 Combination Evaluation <a class="header-anchor" href="#_3-2-combination-evaluation" aria-label="Permalink to &quot;3.2 Combination Evaluation&quot;">​</a></h3><p>For each candidate combination $\\mathbf{m}$, AgentOpt:</p><ol><li>Sets the model assignment via context variables</li><li>Runs the pipeline on a batch of evaluation datapoints</li><li>Records per-call costs, latencies, and final accuracy</li><li>Aggregates results to estimate the combination&#39;s utility</li></ol><p>The cost of a combination is computed as the sum of per-call costs across all stages. Latency is measured end-to-end.</p><h3 id="_3-3-pareto-frontier-export" tabindex="-1">3.3 Pareto Frontier Export <a class="header-anchor" href="#_3-3-pareto-frontier-export" aria-label="Permalink to &quot;3.3 Pareto Frontier Export&quot;">​</a></h3><p>Results are exported as a Pareto frontier over (accuracy, cost, latency), enabling transparent tradeoff analysis. Developers can inspect dominated combinations and select configurations matching their deployment constraints.</p><h2 id="_4-search-algorithms" tabindex="-1">4. Search Algorithms <a class="header-anchor" href="#_4-search-algorithms" aria-label="Permalink to &quot;4. Search Algorithms&quot;">​</a></h2><p>Eight algorithms are implemented for sample-efficient exploration of the combination space:</p><table tabindex="0"><thead><tr><th>Algorithm</th><th>Type</th><th>Key Characteristic</th></tr></thead><tbody><tr><td><strong>Arm Elimination</strong></td><td>Bandit</td><td>Progressively eliminates combinations whose UCB falls below the leader</td></tr><tr><td><strong>UCB-E</strong></td><td>Bandit</td><td>Upper Confidence Bound for Exploration; best in v2</td></tr><tr><td><strong>UCB-E + Low-Rank Factorization</strong></td><td>Bandit</td><td>Extends UCB-E with factorized uncertainty estimates</td></tr><tr><td><strong>Epsilon-LUCB</strong></td><td>Bandit</td><td>Epsilon-greedy variant of Lower Upper Confidence Bound</td></tr><tr><td><strong>Threshold Successive Elimination</strong></td><td>Bandit</td><td>Eliminates arms below a quality threshold</td></tr><tr><td><strong>Bayesian Optimization</strong></td><td>BO</td><td>Effective on smooth quality landscapes</td></tr><tr><td><strong>Hill Climbing</strong></td><td>Local search</td><td>Greedy local improvement; sensitive to local optima</td></tr><tr><td><strong>LM Proposal</strong></td><td>LM-driven</td><td>Uses an LLM to propose candidate combinations</td></tr><tr><td><strong>Random Search</strong></td><td>Baseline</td><td>Uniform random sampling</td></tr><tr><td><strong>Brute-Force</strong></td><td>Baseline</td><td>Evaluates all combinations exhaustively</td></tr></tbody></table><p><strong>Primary result</strong>: UCB-E recovers near-optimal accuracy while reducing the evaluation budget by <strong>62–76%</strong> relative to brute-force search (v2 results). In v1, Arm Elimination provides the most consistent tradeoff, reducing budget by <strong>24–67%</strong> across three of four benchmarks.</p><p>Bayesian Optimization excels on smooth landscapes but struggles with concentrated quality distributions. Hill Climbing is sensitive to neighborhood topology and local optima. LM Proposal fails when optimal combinations depend on non-obvious role interactions.</p><h2 id="_5-experimental-setup" tabindex="-1">5. Experimental Setup <a class="header-anchor" href="#_5-experimental-setup" aria-label="Permalink to &quot;5. Experimental Setup&quot;">​</a></h2><h3 id="_5-1-benchmarks" tabindex="-1">5.1 Benchmarks <a class="header-anchor" href="#_5-1-benchmarks" aria-label="Permalink to &quot;5.1 Benchmarks&quot;">​</a></h3><p>Four benchmarks span reasoning, science QA, math, and tool-use:</p><table tabindex="0"><thead><tr><th>Benchmark</th><th>Domain</th><th>Pipeline Type</th><th>Combinations</th></tr></thead><tbody><tr><td><strong>HotpotQA</strong></td><td>Multi-hop QA</td><td>2-stage planner-solver</td><td>81 (9×9 models)</td></tr><tr><td><strong>MathQA</strong></td><td>Math reasoning</td><td>2-stage answer-critic</td><td>81 (9×9 models)</td></tr><tr><td><strong>GPQA Diamond</strong></td><td>Graduate science QA</td><td>Single model</td><td>9</td></tr><tr><td><strong>BFCL v3</strong></td><td>Tool-use / function-calling</td><td>Single-model agent</td><td>9</td></tr></tbody></table><h3 id="_5-2-model-pool" tabindex="-1">5.2 Model Pool <a class="header-anchor" href="#_5-2-model-pool" aria-label="Permalink to &quot;5.2 Model Pool&quot;">​</a></h3><p>Nine models were evaluated, spanning capability tiers from small open-source models to frontier closed models. The pool includes Ministral 3 8B, Claude Haiku 4.5, Claude Sonnet 4.6, Claude Opus 4.6, and others.</p><h2 id="_6-results" tabindex="-1">6. Results <a class="header-anchor" href="#_6-results" aria-label="Permalink to &quot;6. Results&quot;">​</a></h2><h3 id="_6-1-main-performance-results" tabindex="-1">6.1 Main Performance Results <a class="header-anchor" href="#_6-1-main-performance-results" aria-label="Permalink to &quot;6.1 Main Performance Results&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Benchmark</th><th>Best Combination</th><th>Best Accuracy</th><th>Worst Accuracy</th><th>Cost Ratio (best/worst at matched accuracy)</th></tr></thead><tbody><tr><td>HotpotQA</td><td>Ministral 3 8B (planner) + Claude Opus 4.6 (solver)</td><td>74.27%</td><td>—</td><td>—</td></tr><tr><td>MathQA</td><td>Claude Opus 4.6 (answer) + Claude Haiku 4.5 (critic)</td><td>98.84%</td><td>—</td><td>—</td></tr><tr><td>GPQA Diamond</td><td>Claude Opus 4.6</td><td>74.75%</td><td>—</td><td>—</td></tr><tr><td>BFCL v3</td><td>Multiple models</td><td>70.00%</td><td>—</td><td>32×</td></tr></tbody></table><p><strong>Headline finding</strong>: Across all four benchmarks, the cost gap between best and worst model combinations at matched accuracy ranges from <strong>13× to 32×</strong>.</p><h3 id="_6-2-the-planner-role-inversion-hotpotqa" tabindex="-1">6.2 The Planner Role Inversion (HotpotQA) <a class="header-anchor" href="#_6-2-the-planner-role-inversion-hotpotqa" aria-label="Permalink to &quot;6.2 The Planner Role Inversion (HotpotQA)&quot;">​</a></h3><p>The HotpotQA results provide the most striking illustration of the core thesis:</p><ul><li><strong>Claude Opus 4.6 as planner</strong>: ranks <strong>71st–81st</strong> out of 81 combinations</li><li><strong>Ministral 3 8B as planner</strong> (with Opus 4.6 as solver): <strong>74.27%</strong> — best overall</li><li><strong>Claude Opus 4.6 solo</strong> (planner + solver): <strong>31.71%</strong></li></ul><p>Root cause: Opus 4.6 in the planner role answers queries directly rather than formulating sub-queries for the solver. This &quot;bypasses downstream search tools,&quot; producing poor end-to-end accuracy despite the model&#39;s high individual capability. A weaker planner that properly delegates outperforms a strong one that hoards work.</p><h3 id="_6-3-mathqa-role-specialization" tabindex="-1">6.3 MathQA Role Specialization <a class="header-anchor" href="#_6-3-mathqa-role-specialization" aria-label="Permalink to &quot;6.3 MathQA Role Specialization&quot;">​</a></h3><p>On MathQA (answer-critic pipeline):</p><ul><li><strong>Best configuration</strong>: Opus 4.6 (answer) + Haiku 4.5 (critic) — 98.84%</li><li>The critic role benefits from a lighter model that efficiently validates rather than regenerates answers</li><li>This matches the intuition that verification is computationally cheaper than generation</li></ul><h3 id="_6-4-search-algorithm-efficiency" tabindex="-1">6.4 Search Algorithm Efficiency <a class="header-anchor" href="#_6-4-search-algorithm-efficiency" aria-label="Permalink to &quot;6.4 Search Algorithm Efficiency&quot;">​</a></h3><p>Arm Elimination (v1) and UCB-E (v2) consistently outperform baselines:</p><ul><li><strong>UCB-E</strong> (v2): 62–76% budget reduction vs brute-force</li><li><strong>Arm Elimination</strong> (v1): 24–67% budget reduction across 3/4 benchmarks</li><li><strong>Bayesian Optimization</strong>: strong on smooth landscapes, weak on discontinuous quality distributions</li><li><strong>LM Proposal</strong>: poor when optimal combinations are role-interaction-dependent (LLM cannot anticipate counter-intuitive role dynamics)</li></ul><h2 id="_7-design-principles" tabindex="-1">7. Design Principles <a class="header-anchor" href="#_7-design-principles" aria-label="Permalink to &quot;7. Design Principles&quot;">​</a></h2><p>AgentOpt is built around three core requirements:</p><ol><li><strong>Framework-agnosticism</strong>: No custom wrappers or agent code modifications required; httpx-layer interception ensures compatibility with any LLM framework</li><li><strong>Non-intrusiveness</strong>: Transparent model substitution; existing pipelines work unchanged</li><li><strong>Unified execution substrate</strong>: Single evaluation harness supports all eight search strategies, enabling fair algorithm comparison</li></ol><h2 id="_8-implications-for-agent-system-design" tabindex="-1">8. Implications for Agent System Design <a class="header-anchor" href="#_8-implications-for-agent-system-design" aria-label="Permalink to &quot;8. Implications for Agent System Design&quot;">​</a></h2><h3 id="_8-1-evaluate-pipelines-not-models" tabindex="-1">8.1 Evaluate Pipelines, Not Models <a class="header-anchor" href="#_8-1-evaluate-pipelines-not-models" aria-label="Permalink to &quot;8.1 Evaluate Pipelines, Not Models&quot;">​</a></h3><p>The 13–32× cost gap and the planner inversion phenomenon demonstrate that per-model benchmarks (MMLU, GPQA, SWE-bench) are insufficient for pipeline design decisions. End-to-end evaluation on representative data is necessary.</p><h3 id="_8-2-weak-planner-strong-solver-strong-solo-agent" tabindex="-1">8.2 Weak Planner + Strong Solver &gt; Strong Solo Agent <a class="header-anchor" href="#_8-2-weak-planner-strong-solver-strong-solo-agent" aria-label="Permalink to &quot;8.2 Weak Planner + Strong Solver &gt; Strong Solo Agent&quot;">​</a></h3><p>The HotpotQA result (Ministral 3 8B planner + Opus 4.6 solver: 74.27% vs Opus 4.6 solo: 31.71%) empirically validates the &quot;weak planner + smart delegation&quot; architecture. This is the AgentOpt thesis: optimizing the planner&#39;s delegation behavior, not its raw capability, determines pipeline performance.</p><h3 id="_8-3-search-algorithms-enable-practical-optimization" tabindex="-1">8.3 Search Algorithms Enable Practical Optimization <a class="header-anchor" href="#_8-3-search-algorithms-enable-practical-optimization" aria-label="Permalink to &quot;8.3 Search Algorithms Enable Practical Optimization&quot;">​</a></h3><p>Without sample-efficient search, the combinatorial space ($n^k$ combinations) is intractable. UCB-E and Arm Elimination reduce the evaluation budget by 62–76%, making pipeline optimization practical for real-world deployments with limited labeled data.</p><h2 id="_9-conclusion" tabindex="-1">9. Conclusion <a class="header-anchor" href="#_9-conclusion" aria-label="Permalink to &quot;9. Conclusion&quot;">​</a></h2><p>AgentOpt introduces client-side optimization as a complement to server-side efficiency research for LLM-based agents. The framework demonstrates that:</p><ol><li>Individual model capability rankings do not predict combination performance</li><li>Cost gaps of 13–32× exist between optimal and suboptimal configurations at matched accuracy</li><li>Sample-efficient bandit algorithms (UCB-E, Arm Elimination) recover near-optimal configurations with 62–76% fewer evaluations than brute-force</li><li>The optimal assignment of models to pipeline roles is often counter-intuitive and requires empirical search</li></ol><p>AgentOpt is open-sourced at <a href="https://agentoptimizer.github.io/agentopt/" target="_blank" rel="noreferrer">https://agentoptimizer.github.io/agentopt/</a> to enable reproducibility and community adoption.</p><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li>Agrawal et al. (2024). &quot;Taming Throughput-Latency Tradeoff in LLM Inference with Sarathi-Serve.&quot; OSDI.</li><li>Bubeck et al. (1996–2012). Bandit algorithms survey: UCB, Arm Elimination, Epsilon-LUCB, Successive Elimination.</li><li>Chen et al. (2024). &quot;BFCL: Berkeley Function-Calling Leaderboard.&quot; UC Berkeley.</li><li>Firoozi et al. (2024). &quot;Foundation Models in Robotics.&quot; arXiv:2312.07843.</li><li>Ho et al. (2024). &quot;HotpotQA.&quot; EMNLP 2018 (original benchmark).</li><li>Kwon et al. (2023). &quot;Efficient Memory Management for Large Language Model Serving with PagedAttention.&quot; SOSP.</li><li>Peng et al. (2024). &quot;AgentOpt Codebase.&quot; GitHub: agentoptimizer/agentopt.</li><li>Shahriari et al. (2016). &quot;Taking the Human Out of the Loop: A Review of Bayesian Optimization.&quot; IEEE.</li><li>Wang et al. (2024). &quot;GPQA: A Graduate-Level Google-Proof Q&amp;A Benchmark.&quot; arXiv:2311.12022.</li><li>Wei et al. (2022). &quot;Chain-of-Thought Prompting Elicits Reasoning in Large Language Models.&quot; NeurIPS.</li></ul>',70)])])}const u=e(n,[["render",r]]);export{m as __pageData,u as default};
